package kr.co.iei.member.model.dao; import kr.co.iei.member.model.vo.*; import lombok.RequiredArgsConstructor; import org.apache.ibatis.session.SqlSession; import org.springframework.stereotype.Repository; import java.util.*; @Repository @RequiredArgsConstructor public class MemberDao { private final SqlSession sqlSession; public MemberResponse selectMemberById(Long id){ return sqlSession.selectOne("member.selectMemberById", id);} public int updateMember(Long id, MemberUpdateRequest request){ Map<String,Object> p=new HashMap<>(); p.put("memberId",id); p.put("request",request); return sqlSession.update("member.updateMember", p);} }
